import { collection, addDoc } from 'firebase/firestore';
import { db } from '../config/firebaseConfig';
import { Group, Trip } from '../types';

/**
 * Creates a new Group document in Firestore.
 * The document ID is auto-generated by Firestore and returned as part of the Group object.
 */
export const createGroup = async (
  name: string,
  createdBy: string
): Promise<Group> => {
  const groupsCollection = collection(db, 'groups');
  const docRef = await addDoc(groupsCollection, {
    name,
    createdBy,
  });
  
  return {
    id: docRef.id,
    name,
    createdBy,
  };
};

/**
 * Creates a new Trip document in Firestore, linking it to a Group via groupId.
 * The document ID is auto-generated by Firestore and returned as part of the Trip object.
 */
export const createTrip = async (
  groupId: string,
  name: string,
  startDate: string,
  endDate: string,
  status: string
): Promise<Trip> => {
  const tripsCollection = collection(db, 'trips');
  const docRef = await addDoc(tripsCollection, {
    groupId,
    name,
    startDate,
    endDate,
    status,
  });

  return {
    id: docRef.id,
    groupId,
    name,
    startDate,
    endDate,
    status,
  };
};
